import { Heading as AriaHeading } from 'react-aria-components';
import { cx } from '@/utils/cx';
import { CloseButton } from '@/vendor/untitled-ui/base/buttons/close-button';
import { FeaturedIcon } from '@/vendor/untitled-ui/foundations/featured-icon/featured-icon';
import { BackgroundPattern } from '@/vendor/untitled-ui/shared-assets/background-patterns';

export type { DialogTriggerProps } from 'react-aria-components';

type ModalHeaderProps = {
  featuredIcon?: React.ReactNode;
  featuredIconColor: 'brand' | 'gray' | 'success' | 'warning' | 'error';
  title?: React.ReactNode;
  subtitle?: React.ReactNode;
  onClose?: () => void;
  dataId?: string;
  withDividers: boolean;
};

export function ModalHeader({
  featuredIcon,
  featuredIconColor,
  title,
  subtitle,
  onClose,
  dataId,
  withDividers,
}: ModalHeaderProps) {
  return (
    <div
      className={cx(
        'mx-4 mt-4 sm:mx-6 sm:mt-6',
        withDividers || subtitle ? 'mb-3 sm:mb-5' : '',
      )}
    >
      <div className="flex justify-between">
        <div>
          {featuredIcon ? (
            <div className="relative w-max mb-4">
              <FeaturedIcon
                size="lg"
                color={featuredIconColor}
                icon={featuredIcon}
              />
              <BackgroundPattern
                pattern="circle"
                size="sm"
                className="text-gray-200 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2"
              />
            </div>
          ) : null}
          {title ? (
            <AriaHeading
              slot="title"
              className="relative z-2 text-md font-semibold text-primary"
            >
              {title}
            </AriaHeading>
          ) : null}
        </div>
        {onClose ? (
          <CloseButton
            className="w-6 h-6"
            onClick={onClose}
            data-id={`${dataId}-close-button`}
          />
        ) : null}
      </div>

      {subtitle ? (
        <p className="relative z-2 text-sm text-tertiary">{subtitle}</p>
      ) : null}
    </div>
  );
}
