import {
  DialogTrigger as AriaDialogTrigger,
  type DialogTriggerProps,
} from 'react-aria-components';
import {
  Modal as BaseModal,
  Dialog as BaseDialog,
  ModalOverlay as BaseModalOverlay,
} from '@/vendor/untitled-ui/application/modals/modal';
import { cx } from '@/utils/cx';
import { WithDataId } from '@/types/withDataId';
import { ModalHeader } from './ModalHeader';

export type { DialogTriggerProps } from 'react-aria-components';

export function DialogTrigger(props: DialogTriggerProps) {
  return <AriaDialogTrigger {...props} />;
}

const styles = {
  sm: {
    root: 'max-w-[420px] sm:min-w-[420px]',
  },
  md: {
    root: 'max-w-[568px] sm:min-w-[568px]',
  },
  lg: {
    root: 'max-w-[720px] md:min-w-[720px]',
  },
  xl: {
    root: 'max-w-[960px] lg:min-w-[960px]',
  },
};

export type ModalProps = React.PropsWithChildren<
  React.ComponentProps<typeof BaseModal>
> &
  WithDataId & {
    onClose?: () => void;
    title?: React.ReactNode;
    subtitle?: React.ReactNode;
    actions?: React.ReactNode;
    featuredIcon?: React.ReactNode;
    featuredIconColor?: 'brand' | 'gray' | 'success' | 'warning' | 'error';
    withDividers?: boolean;
    size?: 'sm' | 'md' | 'lg' | 'xl';
  };

export function Modal({
  children,
  isOpen,
  title,
  subtitle,
  actions,
  onClose,
  featuredIcon,
  featuredIconColor = 'success',
  isDismissable = true,
  withDividers = false,
  'data-id': dataId,
  size = undefined,
  isKeyboardDismissDisabled,
  shouldCloseOnInteractOutside,
  ...props
}: ModalProps) {
  return (
    <BaseModalOverlay
      isOpen={isOpen}
      onOpenChange={(nextIsOpen) => {
        if (!nextIsOpen && onClose) {
          onClose();
        }
      }}
      isDismissable={isDismissable}
      isKeyboardDismissDisabled={isKeyboardDismissDisabled}
      shouldCloseOnInteractOutside={shouldCloseOnInteractOutside}
    >
      <BaseModal
        {...props}
        className={cx(
          'pointer-events-none',
          typeof props.className === 'string' ? props.className : '',
        )}
      >
        <BaseDialog className="pointer-events-none">
          <div
            className={cx(
              'pointer-events-auto relative flex max-h-[calc(100dvh-4rem)] flex-col overflow-hidden rounded-2xl bg-primary shadow-xl',
              size ? styles[size].root : '',
            )}
            data-id={dataId}
          >
            <ModalHeader
              featuredIcon={featuredIcon}
              featuredIconColor={featuredIconColor}
              title={title}
              subtitle={subtitle}
              onClose={onClose}
              dataId={dataId}
              withDividers={withDividers}
            />
            {withDividers ? (
              <div className="h-px w-full shrink-0 bg-border-secondary" />
            ) : null}
            {children ? (
              <div
                className={cx(
                  'min-h-0 flex-1 z-1 overflow-y-auto px-4 sm:px-6 text-sm text-tertiary',
                  withDividers ? 'pt-4 sm:pt-5' : 'pt-0.5',
                  actions && !withDividers ? '' : 'pb-4 sm:pb-6',
                )}
              >
                {children}
              </div>
            ) : null}
            {withDividers && actions ? (
              <div className="h-px w-full shrink-0 bg-border-secondary" />
            ) : null}
            {actions ? (
              <div className="shrink-0 grid grid-flow-col auto-cols-fr items-center gap-3 px-4 py-4 sm:px-6 sm:py-6">
                {actions}
              </div>
            ) : null}
          </div>
        </BaseDialog>
      </BaseModal>
    </BaseModalOverlay>
  );
}
